import { Component, EventEmitter, h, Prop, State, Event, Method } from '@stencil/core';
import { SlidersHorizontalIcon } from '../../subcomponents/svg/Svg';
import { CONTAINER_WIDTH, MOBILE_BREAKPOINT } from '../../constants/breakpoints';

@Component({
  tag: 'personalize-filter',
  styleUrl: 'personalize-filter.css',
  shadow: true,
})

export class PersonalizeFilter {

  @Prop() filterHeader: string;
  @Prop() clearFilterTitle: string;
  @Prop() resultButtonTemplate: string;
  @Prop() noResultFoundButtonTitle: string;
  @Prop() resultCount: number = 0;
  @Prop() alwaysMobile: boolean = false; // Stay in mobile mode (for sheet usage)
  @Prop() filters: {
    id: string;
    label: string;
    options: {
      value: string;
      label: string;
      swatch?: string[];
    }[];
  }[] = [];
  @Prop({ mutable: true }) selectedFilters: { [key: string]: string[] } = {}; // groupId -> selected option values
  private initialSnapshot: { [key: string]: string[] } | null = null;
  private selectedChipsEl?: HTMLElement;
  private resizeObserver?: ResizeObserver;
  private chipRefs: Map<string, HTMLChipComponentElement> = new Map();
  private overflowChipProbeEl?: HTMLElement;
  private chipWidthCache = new Map<string, number>();
  @State() overflowChipWidth: number = 50; // fallback, smallest possible count chip width
  @Event() applyFilters: EventEmitter<{ [key: string]: string[] }>;
  @Event() rollbackFilters: EventEmitter<{ [key: string]: string[] }>;
  @State() openGroup: string | null = null; // track which filter group is open
  @State() isMobile: boolean = typeof window !== 'undefined' ? window.innerWidth <= MOBILE_BREAKPOINT : false;
  @Event() requestClose: EventEmitter<void>;
  @Event() filterChange: EventEmitter<{ [key: string]: string[] }>;
  @State() selectedChipContainerWidth: number = 0;
  @State() visibleChips: { [groupId: string]: string[] } = {};
  @State() hiddenChipCounts: { [groupId: string]: number } = {};

  componentWillLoad() {
    this.updateIsMobile();
    if (Array.isArray(this.filters) && Object.keys(this.selectedFilters).length === 0) {
      const obj = {};
      this.filters.forEach(f => { obj[f.id] = []; });
      this.selectedFilters = obj;
    }
  }

  @Method()
  async startSession() {
    this.initialSnapshot = JSON.parse(JSON.stringify(this.selectedFilters || {}));
  }

  @Method()
  async rollbackToInitial() {
    if (this.initialSnapshot) {
      this.selectedFilters = JSON.parse(JSON.stringify(this.initialSnapshot));
      this.filterChange.emit(this.selectedFilters);
      this.requestClose.emit();
      this.rollbackFilters.emit(this.selectedFilters);
      this.initialSnapshot = null;
    } else {
      this.requestClose.emit();
    }
  }

  @Method()
  async commitAndClose() {
    this.applyFilters.emit(this.selectedFilters);
    this.initialSnapshot = null;
    this.requestClose.emit();
  }

  componentDidLoad() {
    window.addEventListener('resize', this.handleResize);
  }

  private _currentProbeOverflowValue(): number {
    return Math.max(0, ...Object.values(this.hiddenChipCounts));
  }

  private updateVisibleChips = () => {
    if (!this.selectedChipsEl) {
      return;
    }

    requestAnimationFrame(() => {
      this.chipRefs.forEach((el, key) => {
        const width = el.getBoundingClientRect().width;
        if (width > 0) {
          this.chipWidthCache.set(key, width);
        }
      });

      requestAnimationFrame(() => {
        const updates: { [groupId: string]: string[] } = {};
        const hiddenUpdates: { [groupId: string]: number } = {};
        this.filters.forEach(group => {
          const result = this.getVisibleChipsForGroup(group.id);
          if (Array.isArray(result)) {
            const visible = result;
            const hidden = (this.selectedFilters[group.id] || []).length - visible.length;
            if (
              JSON.stringify(this.visibleChips[group.id]) !== JSON.stringify(visible) ||
              this.hiddenChipCounts[group.id] !== hidden
            ) {
              updates[group.id] = visible;
              hiddenUpdates[group.id] = hidden;
            }
          }
        });
        if (Object.keys(updates).length > 0) {
          this.visibleChips = { ...this.visibleChips, ...updates };
          this.hiddenChipCounts = { ...this.hiddenChipCounts, ...hiddenUpdates };
        }
      });
    });
  }

  private resizeHandler = (entries: ResizeObserverEntry[]) => {
    for (const entry of entries) {
      const w = entry.contentRect.width;
      if (this.selectedChipContainerWidth !== w) {
        this.selectedChipContainerWidth = w;
        this.updateVisibleChips();
      }
    }
  }

  componentDidRender() {
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
      this.resizeObserver = undefined;
    }

    if (this.selectedChipsEl) {
      this.resizeObserver = new ResizeObserver(this.resizeHandler);
      this.resizeObserver.observe(this.selectedChipsEl);
      this.updateVisibleChips();
    }
  }

  disconnectedCallback() {
    window.removeEventListener('resize', this.handleResize);
    if (this.resizeObserver) {
      this.resizeObserver.disconnect();
      this.resizeObserver = undefined;
    }
    this.chipWidthCache.clear();
  }

  getVisibleChipsForGroup(groupId: string): string[] | undefined {
    if (!this.selectedChipsEl) {
      return undefined;
    }
    const containerWidth = this.selectedChipsEl.clientWidth;
    const selected = this.selectedFilters[groupId] || [];
    const gap = 4; // gap between chips in px as per figma
    if (this.overflowChipProbeEl) {
      const chip = this.overflowChipProbeEl.querySelector('chip-component');
      if (chip) {
        const width = (chip as HTMLChipComponentElement).getBoundingClientRect().width;
        if (width && width !== this.overflowChipWidth) {
          this.overflowChipWidth = width;
        }
      }
    }
    const overflowChipWidth = this.overflowChipWidth;
    const visible: string[] = [];
    let usedWidth = 0;
    for (let i = 0; i < selected.length; i++) {
      const sel = selected[i];
      const chipEl = this.chipRefs.get(sel);
      const cachedWidth = this.chipWidthCache.get(sel);
      const measuredWidth = chipEl ? chipEl.getBoundingClientRect().width : 161; // smallest possible chip width
      const chipWidth = cachedWidth || measuredWidth;
      const overflow = selected.length - (i + 1) > 0;
      let projectedWidth = usedWidth;
      projectedWidth += chipWidth + (visible.length > 0 ? gap : 0);
      if (overflow) {
        projectedWidth += overflowChipWidth + gap;
      }
      if (
        (visible.length === 0 && projectedWidth - (overflow ? (overflowChipWidth + gap) : 0) <= containerWidth) ||
        projectedWidth <= containerWidth
      ) {
        visible.push(sel);
        usedWidth += chipWidth + (visible.length > 1 ? gap : 0);
      } else {
        break;
      }
    }
    return visible;
  }

  private handleResize = () => {
    this.updateIsMobile();
  };

  private updateIsMobile = () => {
    if (this.alwaysMobile) {
      this.isMobile = true;
      return;
    }
    const mobile = window.innerWidth <= MOBILE_BREAKPOINT;
    if (mobile !== this.isMobile) {
      this.isMobile = mobile;
    }
  };

  toggleOpenGroup = (groupId: string) => {
    this.openGroup = (this.openGroup === groupId) ? null : groupId;
  }

  handleOptionCheck = (groupId: string, value: string) => {
    const current = this.selectedFilters[groupId] || [];
    const set = new Set(current);
    set.has(value) ? set.delete(value) : set.add(value);
    this.selectedFilters = {
      ...this.selectedFilters,
      [groupId]: Array.from(set),
    };
    // Emit change after user action
    this.filterChange.emit(this.selectedFilters);
  }

  handleChipClose = (groupId: string, value: string) => {
    this.selectedFilters = {
      ...this.selectedFilters,
      [groupId]: this.selectedFilters[groupId].filter(v => v !== value),
    };
    // Emit change after user action
    this.filterChange.emit(this.selectedFilters);
  }

  clearFilters = () => {
    const cleared = {};
    this.filters.forEach(group => { cleared[group.id] = []; });
    this.selectedFilters = cleared;
    // Emit change after user action
    this.filterChange.emit(this.selectedFilters);
  }

  private isClearFilterDisabled(): boolean {
    return !Object.values(this.selectedFilters).some(arr => arr.length > 0);
  }

  // Accessibility =>

  handleKeyDownClose = (event: KeyboardEvent) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      this.requestClose.emit();
    }
  };

  handleKeyDownClearFilters = (event: KeyboardEvent) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      if (!this.isClearFilterDisabled()) this.clearFilters();
    }
  };

  handleCheckboxKeyDown = (event: KeyboardEvent, groupId: string, value: string) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      this.handleOptionCheck(groupId, value);
    }
  };

  handleChipKeyDown = (event: KeyboardEvent, groupId: string, value: string) => {
    if (event.key === 'Enter' || event.key === ' ') {
      event.preventDefault();
      event.stopPropagation();
      this.handleChipClose(groupId, value);
    }
  };

  render() {

    if (this.isMobile) {
      return (
        <div class="personalize-mobile-sheet">
          <div class="icon-header">
            <div
              class="close-icon-container"
              id="closeIcon"
              tabIndex={0}
              aria-label="Close"
              onClick={() => { this.rollbackToInitial(); }}
              onKeyDown={this.handleKeyDownClose}
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 16 16" fill="none">
                <path d="M15.281 14.2194C15.3507 14.2891 15.406 14.3718 15.4437 14.4629C15.4814 14.5539 15.5008 14.6515 15.5008 14.7501C15.5008 14.8486 15.4814 14.9462 15.4437 15.0372C15.406 15.1283 15.3507 15.211 15.281 15.2807C15.2114 15.3504 15.1286 15.4056 15.0376 15.4433C14.9465 15.4811 14.849 15.5005 14.7504 15.5005C14.6519 15.5005 14.5543 15.4811 14.4632 15.4433C14.3722 15.4056 14.2895 15.3504 14.2198 15.2807L8.00042 9.06036L1.78104 15.2807C1.64031 15.4214 1.44944 15.5005 1.25042 15.5005C1.05139 15.5005 0.860523 15.4214 0.719792 15.2807C0.579062 15.1399 0.5 14.9491 0.5 14.7501C0.5 14.551 0.579062 14.3602 0.719792 14.2194L6.9401 8.00005L0.719792 1.78068C0.579062 1.63995 0.5 1.44907 0.5 1.25005C0.5 1.05103 0.579062 0.860156 0.719792 0.719426C0.860523 0.578695 1.05139 0.499634 1.25042 0.499634C1.44944 0.499634 1.64031 0.578695 1.78104 0.719426L8.00042 6.93974L14.2198 0.719426C14.3605 0.578695 14.5514 0.499634 14.7504 0.499634C14.9494 0.499634 15.1403 0.578695 15.281 0.719426C15.4218 0.860156 15.5008 1.05103 15.5008 1.25005C15.5008 1.44907 15.4218 1.63995 15.281 1.78068L9.06073 8.00005L15.281 14.2194Z" fill="#191919" />
              </svg>
            </div>
          </div>
          <div class="personalize-title">{this.filterHeader}</div>
          <div class="container-body">
            {this.filters.map(group => (
              <div class="mobile-section" key={group.id}>
                <div class="mobile-section-header">
                  <div class="mobile-section-label">{group.label}</div>
                </div>
                <div class="chip-row">
                  {group.options.map(option => (
                    <chip-component
                      key={option.value}
                      label={option.label}
                      colors={option.swatch ? option.swatch.join(',') : undefined}
                      selectable={true}
                      selected={!!(this.selectedFilters[group.id]?.includes(option.value))}
                      onChipSelect={() => this.handleOptionCheck(group.id, option.value)}
                      onKeyDown={e => this.handleChipKeyDown(e, group.id, option.value)}
                    />
                  ))}
                </div>
              </div>
            ))}
          </div>
          <div class="mobile-footer">
            <div
              class={`clear-filters__mobile${this.isClearFilterDisabled() ? ' clear-filters__mobile--disabled' : ''}`}
              onClick={this.isClearFilterDisabled() ? undefined : this.clearFilters}
              aria-disabled={this.isClearFilterDisabled() ? 'true' : 'false'}
              tabIndex={this.isClearFilterDisabled() ? -1 : 0}
              onKeyDown={this.handleKeyDownClearFilters}
            >{this.clearFilterTitle}</div>
            <div class={`clr-filter-btn${this.resultCount === 0 ? ' clr-filter-btn--disabled' : ''}`}>
              <button-component
                onClick={() => this.commitAndClose()}
                label="clear-filter-btn"
                isArrow={false}
                btndisabled={this.resultCount === 0 ? 'Yes' : 'No'}
              >
                {this.resultCount === 0
                  ? this.noResultFoundButtonTitle
                  : this.resultButtonTemplate.replace('{count}', this.resultCount.toString())}
              </button-component>
            </div>
          </div>
        </div>
      );
    } else {
      return (
        <div class="personalize-filter-container">
          <div class="filter-header">
            <div class="filter-caption">
              <span class="filter-icon" aria-hidden="true">
                <SlidersHorizontalIcon className="filter-svg" />
              </span>
              <h3 class="filter-title">{this.filterHeader}</h3>
            </div>
            <h4
              class={`clear-filters${this.isClearFilterDisabled() ? ' clear-filters--disabled' : ''}`}
              onClick={this.isClearFilterDisabled() ? undefined : this.clearFilters}
              aria-disabled={this.isClearFilterDisabled() ? 'true' : 'false'}
              tabIndex={this.isClearFilterDisabled() ? -1 : 0}
              onKeyDown={this.handleKeyDownClearFilters}
            >
              {this.clearFilterTitle}
            </h4>
          </div>

          {this.filters.map((group) => {
            const chipsSelectedAndClosed =
              (this.openGroup !== group.id) &&
              (this.selectedFilters[group.id]?.length ?? 0) > 0;
            // Min width of container
            const limit = this.selectedChipContainerWidth > 0 && this.selectedChipContainerWidth <= CONTAINER_WIDTH;
            const calcMaxWidth = limit ? '160px' : undefined;
            // Ensures atleast one chip is visible in small width containers
            return (
              <div class="filter-accordion-block" key={group.id}>
                <accordion-component
                  noBottomPadding={chipsSelectedAndClosed}
                  headline={group.label}
                  open={this.openGroup === group.id}
                  onAccordionToggle={() => this.toggleOpenGroup(group.id)}
                >

                  {this.openGroup === group.id && (
                    <div class="filter-options-list">
                      <span 
                        aria-live="polite" 
                        aria-atomic="true" 
                        class="visually-hidden"
                      >
                        {`${this.selectedFilters[group.id]?.length} of ${group.options.length} filter selected. `}
                      </span>
                      {group.options.map((option, id) => (
                        <checkbox-component
                          showBorder={id !== group.options.length - 1}
                          checked={(this.selectedFilters[group.id] || []).includes(option.value)}
                          label={option.label}
                          colors={option.swatch ? option.swatch.join(',') : undefined}
                          onCheckboxChange={() => {
                            this.handleOptionCheck(group.id, option.value);
                          }}
                          onKeyDown={e => this.handleCheckboxKeyDown(e, group.id, option.value)}
                        />
                      ))}
                    </div>
                  )}
                </accordion-component>

                {chipsSelectedAndClosed && (
                  <div class="selected-chips" ref={el => this.selectedChipsEl = el}>
                    {(this.visibleChips[group.id] || []).map(sel => (
                      <chip-component
                        ref={el => {
                          if (el) this.chipRefs.set(sel, el);
                          else this.chipRefs.delete(sel);
                        }}
                        key={sel}
                        showIcon={true}
                        label={group.options.find(opt => opt.value === sel)?.label || sel}
                        onChipClose={() => this.handleChipClose(group.id, sel)}
                        maxWidth={calcMaxWidth}
                      />
                    ))}
                    {(this.hiddenChipCounts[group.id] ?? 0) > 0 && (
                      <chip-component label={`+${this.hiddenChipCounts[group.id]}`} />
                    )}
                  </div>

                )}
              </div>
            );
          })}
          <div
            style={{ visibility: 'hidden', position: 'absolute', pointerEvents: 'none', overflow: 'hidden' }}
            ref={el => { this.overflowChipProbeEl = el; }}
          >
            <chip-component label={`+${this._currentProbeOverflowValue()}`} />
          </div>
        </div>
      );
    }
  }





}








